# open RFC csv file
def open_RFC_file(filename):
    df = pd.read_csv(filename)
    return df

# save pandas df 
def save_RFC_file(df, filename):
    df.to_csv(filename, index = True)


# use DBScan to identify which blobs are part of the object
# NOTE: all of positions and sizes are done by pixel/pixel size
def run_dbscan(fits_hdr, cat_data, maj, eps_factor, min_samples):

    # w --> ra, h --> dec
    # Note: want in arcseconds (multiply by 3600)
    x_delt = fits_hdr['CDELT1'] * 3600 
    y_delt = fits_hdr['CDELT2'] * 3600 

    # get ras and decs for the blobs
    cat_ras = cat_data['Xposn']
    cat_decs = cat_data['Yposn']

    # get the major, minor axes, and the rotation angle
    assert(abs(x_delt) == abs(y_delt))
    cat_majs = cat_data['Maj']*3600/abs(x_delt)

    # calculate SNR
    rms = fits_hdr['NOISE']
    peak_fluxes = cat_data['Peak_flux']
    cat_snr = peak_fluxes/rms

    # variables for eps in DBSCAN
    Beam_Maj = fits_hdr['BMAJ']*3600/abs(x_delt)
    Blob_Maj = np.max(cat_majs)

    # data and weights
    data = np.column_stack((cat_ras, cat_decs))
    weights = cat_snr

    # choose to use beam or blob major axis
    if maj == 'Beam': 
        BMaj = Beam_Maj
    elif maj == 'Blob': 
        BMaj = Blob_Maj
    else: assert(False)
    
    # create DBSCAN
    db = DBSCAN(eps = BMaj*eps_factor, min_samples = min_samples).fit(data, weights)
    labels = db.labels_

    # Number of clusters in labels, ignoring noise if present.
    n_clusters_ = len(set(labels)) - (1 if -1 in labels else 0)

    (blob_inds, ) = np.where(labels != -1)
    return n_clusters_, blob_inds


# check to see if the blob with the peak pixel is in blob_inds
# if not, add it into the list
def check_peak_blob(cat_data, blob_inds):

    # get fluxes from catalog
    peak_fluxes = cat_data['Peak_flux']

    # get the location of the peak blob
    peak_blob = np.argmax(peak_fluxes)

    # check to see if index is in blob_inds
    if peak_blob not in blob_inds: return np.append(blob_inds, peak_blob)
    else: return blob_inds

# return the total flux of the object given the indices of the blob
def get_tot_flux(cat_data, sep_flux_ind):

    cat_flux = cat_data['Total_flux']

    return np.sum(cat_flux[sep_flux_ind])

# parametric equation for x for an ellipse with rotation and include center
# a: major axis, b: minor axis, theta: angle of major axis measured east of north (in radians)
def fun_x(a, b, theta, t, h, h0):
    x = a * np.cos(t) * np.cos(theta) - b * np.sin(t) * np.sin(theta) + (h - h0)
    return np.append(x, (h-h0)*3600)

# parametric equation for y for an ellipse with rotation and include center
# a: major axis, b: minor axis, theta: angle of major axis measured east of north (in radians)
def fun_y(a, b, theta, t, k, k0):
    y = a * np.cos(t) * np.sin(theta) + b * np.sin(t) * np.cos(theta) + (k - k0)
    return np.append(y, (k-k0)*3600)

# get the size of the object (peak --> outerpart of ellipse)
def get_size(cat_data, blob_inds, Maj_type):

    # return 0 if no blobs in cluster
    if len(blob_inds) == 0: return 0

    # get ras and decs for the blobs
    cat_ras = cat_data['RA']
    cat_decs = cat_data['DEC']

    if Maj_type == 'DC':
    # get the major, minor axes, and the rotation angle
        cat_majs = cat_data['DC_Maj']*3600
        cat_mins = cat_data['DC_Min']*3600
        cat_theta = cat_data['DC_PA']

    elif Maj_type == 'C':
    # get the major, minor axes, and the rotation angle
        cat_majs = cat_data['Maj']*3600
        cat_mins = cat_data['Min']*3600
        cat_theta = cat_data['PA']

    # find brightest blob 
    peak_fluxes = cat_data['Peak_flux']
    peak_ind = np.argmax(peak_fluxes)
    h0 = cat_ras[peak_ind]
    k0 = cat_decs[peak_ind]

    # keep track of largest size
    max_size = 0

    # a: major axis, b: minor axis, theta: angle of major axis measured east of north (in radians)
    for blob_ind in blob_inds: 
        b = cat_mins[blob_ind]
        a = cat_majs[blob_ind]
        theta = np.pi/2 - (cat_theta[blob_ind]*np.pi/180)

        # center of ellipses (h,k) --> (ra, dec)
        h = cat_ras[blob_ind]
        k = cat_decs[blob_ind]
        t = np.arange(0, 2*np.pi, 100)

        # get the x distance and y distance
        xL = fun_x(a, b, theta, t, h, h0)
        yL = fun_y(a, b, theta, t, k, k0)

        # get the maximum distance for this ellipse
        size = np.max(np.sqrt(xL**2 + yL**2))

        # check if the max size needs to be updated
        if size > max_size: max_size = size

    return max_size


# loop through all of the objects
# for obj in objects:
def create_cluster_blob_row(obj):

    # path of folder
    folder = root_path + obj
    fits_folder = fits_path + obj
    
    # take care of the cases where I moved the folder out due to beam size issue or FDR thresholding issue
    if not os.path.exists(folder): return []

    # loop through files
    for _, _, filenames in os.walk(folder):

        if filenames:
            length = len(filenames)
            if length == 0: return []

            # go through each observation
            filenames.sort()
            len_num = len(file_types)

            # list to hold until end of loop, then return 
            temp_row = []
            for l in range(length//len_num):
                filename = filenames[l*len_num]
                # print(filename)

                # handle analyst (zb) case --> only analyst with two letter code
                if filename[26] == '_': i = 30
                else: i = 31

                file = filename[0:i]
                file_path = fits_folder + '/' + file + '.fits'
                catalog_path = folder + '/' + file + '_catalog.fits'
    
                # get the ra and dec data from the catalog
                cat_hdul = fits.open(catalog_path)
                cat_hdul.verify('fix')
                cat_data = cat_hdul[1].data

                # get the ra and the dec of the center of the fits image
                fits_hdul = fits.open(file_path)
                fits_hdul.verify('fix')
                fits_hdr = fits_hdul[0].header

                # number of blobs detected and listed in the catalogue
                num_blobs = len(cat_data)

                # convert hh:mm:ss to degrees
                c = SkyCoord(ra=fits_hdr['RA'], dec=fits_hdr['DEC'], unit=(u.hourangle, u.deg))
                fits_ra_deg = c.ra.degree
                fits_dec_deg = c.dec.degree

                # skip if rms not available in fits
                if ('NOISE' not in fits_hdr):
                    move_path = 'astrogeo/no_noise/' + file

                    # create a folder path for new location
                    if not os.path.exists(move_path):
                        os.makedirs(move_path)

                    # move all of the files from current folder to new folder
                    # files  = os.listdir(fits_folder)
                    for f in file_types:
                        src_path = os.path.join(fits_folder, file + f)
                        dst_path = os.path.join(move_path, file + f)
                        shutil.move(src_path, dst_path)
                    
                    # close both hdul files
                    cat_hdul.close()
                    fits_hdul.close()

                    continue

                else:

                    # dbscan for clusters
                    n_clusters_, blob_inds = run_dbscan(fits_hdr, cat_data, maj, eps_factor, min_samples)

                    blob_inds = check_peak_blob(cat_data, blob_inds)
                    blob_count = len(blob_inds)

                    if Maj_type == 'C':
                        cat_majs = cat_data['Maj']*3600
                        cat_mins = cat_data['Min']*3600
                    elif Maj_type == 'DC':
                        cat_majs = cat_data['DC_Maj']*3600
                        cat_mins = cat_data['DC_Min']*3600

                    Majs = cat_majs[blob_inds].tolist()
                    Mins = cat_mins[blob_inds].tolist()

                    if n_clusters_ == 0: continue

                    # save the ra and dec of the blobs
                    cat_ras = cat_data['RA']*3600
                    cat_decs = cat_data['DEC']*3600

                    # get the size and flux associated with identified blobs in cluster
                    size = get_size(cat_data, blob_inds, Maj_type)
                    tot_flux = get_tot_flux(cat_data, blob_inds)

                    # create row of data
                    # change quantites from deg to arcsec (BMaj, BMin, Size)
                    row = {'Obj_Name': obj, 'Band': filename[11], 'Obs_Date': fits_hdr['DATE-OBS'], 'Filename': file, 'Num_Blobs': num_blobs, 'N_Clusters': n_clusters_, 'Blob_Inds': blob_inds.tolist(), 'Blob_Count': blob_count, 'Blob_Ras': cat_ras.tolist(), 'Blob_Decs': cat_decs.tolist(), 'Majs': Majs, 'Mins': Mins, 'Size': size, 'Tot_Flux': tot_flux, 'Ra': fits_ra_deg, 'Dec': fits_dec_deg, 'BMaj': fits_hdr['BMAJ']*3600, 'BMin': fits_hdr['BMIN']*3600, 'BPa': fits_hdr['BPA']}

                    # add row to data list
                    temp_row += [row]
            
            # return row of  info       
            return temp_row

# create a pandas df with cluster blob info for all of the objects and save as csv
def make_cluster_blob_file(objects, save_data_filename):

    pool = Pool(16)
    data = pool.map(create_cluster_blob_row, objects)

    new_data = []
    for row in data:
        if row == []: continue
        else: new_data += row

    # convert data to pandas dataframe and save
    df = pd.DataFrame(new_data)
    save_RFC_file(df, save_data_filename)


# format the redshift and type column
def format_cross_match(filename):

    # open the csv file
    df = pd.read_csv(filename)

    # only get objects with redshifts
    z_type_df = df[df['z'] != '      ']
    z_type_df['z'] = z_type_df['z'].astype(float)
    z_type_df = z_type_df.loc[z_type_df['z'] > 0]

    # only get valid source types and format the strings
    z_type_df = z_type_df[z_type_df['type'] != '      \n']
    z_type_df = z_type_df[z_type_df['type'] != '       ']
    types = z_type_df['type'].str[:6]
    z_type_df['type'] = types.str.strip()

    # reformat the name of the objects
    z_type_df['Name'] = z_type_df['Name'].str[4:]

    # only get certain columns
    z_type_df = z_type_df[['Name', 'z', 'type']]

    # exclude rows that are star/star-like
    starL = ['Q_Lens', 'Blue*', 'Red*', '*', '!*', '!V*', 'SN']
    for star in starL:
        z_type_df = z_type_df[z_type_df['type'] != star]

    # rename Name to Obj_Name (to be the same as the eps catalog)
    z_type_df.rename(columns={'Name': 'Obj_Name'}, inplace=True)

    return z_type_df

# add the redshift and source type to the main file
def combine_cross_match(eps_filename, z_type_df):

    eps_df = open_RFC_file(eps_filename)
    merged_df = pd.merge(eps_df, z_type_df, on='Obj_Name', how = 'left')

    return merged_df
    
# only need to run once
# given the redshift and the angular distance, calculate the physical size
def add_phys_size(df):

    # get the redshifts and the angular sizes of the objects
    # make sure there aren't any nas
    new_df = df[df['z'].notna()]

    zL = list(new_df['z'])
    sizeL = list(new_df['Size']) * u.arcsec
    sizeL = sizeL.to(u.rad)

    # use Planck15 cosmolgy (was used for TRECS)
    cosmo = Planck15

    # get the physical size in kpc
    angular_diameter_distance = cosmo.angular_diameter_distance(zL)
    physical_size = sizeL.value * angular_diameter_distance
    physical_size_kpc = physical_size.to(u.kpc)

    new_df['Phys_Size'] = physical_size_kpc.value

    return new_df

# remove unresolved objects
# only look at S, C, and X bands objects in the RFC df and RFC crossmatch df to avoid SED effects
def format_crossmatch_RFC(RFC_df, RFC_crossmatch_df, unrevolvedL):

    # remove unresolved objects from RFC df and RFC merged df
    for unresolved_filename in unrevolvedL:
        RFC_df = RFC_df[RFC_df['Filename'] != unresolved_filename[:-2]]
        RFC_crossmatch_df = RFC_crossmatch_df[RFC_crossmatch_df['Filename'] != unresolved_filename[:-2]]

    # only look at S, C, and X band objects in RFC df and RFC RFC_crossmatch_df df to avoid SED effects
    RFC_df = RFC_df[RFC_df['Band'].isin(['S', 'C', 'X'])]
    RFC_crossmatch_df = RFC_crossmatch_df[RFC_crossmatch_df['Band'].isin(['S', 'C', 'X'])]

    # rename columns
    RFC_inds = RFC_df['Unnamed: 0']
    RFC_df['RFC_inds'] = RFC_inds
    RFC_crossmatch_inds = RFC_crossmatch_df['Unnamed: 0']
    RFC_crossmatch_df['RFC_inds'] = RFC_crossmatch_inds

    # reset index of rows after removing unresolved objects and only looking at S, C, and X band objects
    RFC_df.reset_index(drop=True, inplace=True)
    RFC_crossmatch_df.reset_index(drop=True, inplace=True)
    
    return RFC_df, RFC_crossmatch_df


